#include <omp.h>
#include <stdlib.h>
#include <stdio.h>
#include <limits.h>
#include <stdbool.h>
#include <sys/time.h>

#ifndef DEFAULT_ORDER
#define DEFAULT_ORDER 256
#endif

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices [DEFAULT_ORDER + 1];
	int  keys [DEFAULT_ORDER + 1];
	bool is_leaf;
	int num_keys;
} knode; 

void 
findK(	long height,
		knode *knodesD,
		long knodes_elem,
		record *recordsD,

		long *currKnodeD,
		long *offsetD,
		int *keysD, 
		record *ansD,
		int count,
		int order)
{
	int local_size = (order < 1024) ? order : 1024;
	int num_blocks = count;

	#pragma omp parallel for num_threads(num_blocks)
	for(int bid = 0; bid < num_blocks; bid++) {
		int thid;
		long current_knode = currKnodeD[bid];
		long offset_val = offsetD[bid];
		int search_key = keysD[bid];

		for(int i = 0; i < height; i++) {
			knode *current_node_ptr = &knodesD[current_knode];
			int found_thid = -1;

			for(thid = 0; thid < local_size; thid++) {
				if(thid < current_node_ptr->num_keys - 1) {
					if((current_node_ptr->keys[thid] <= search_key) && 
					   (current_node_ptr->keys[thid+1] > search_key)) {
						found_thid = thid;
						break;
					}
				}
			}

			if(found_thid != -1) {
				if(knodesD[offset_val].indices[found_thid] < knodes_elem) {
					offset_val = knodesD[offset_val].indices[found_thid];
				}
			}

			current_knode = offset_val;
		}

		knode *final_node_ptr = &knodesD[current_knode];
		int found_final_thid = -1;
		for(thid = 0; thid < local_size; thid++) {
			if(thid < final_node_ptr->num_keys - 1) {
				if(final_node_ptr->keys[thid] == search_key) {
					found_final_thid = thid;
					break;
				}
			}
		}

		if(found_final_thid != -1) {
			ansD[bid].value = recordsD[final_node_ptr->indices[found_final_thid]].value;
		}

		currKnodeD[bid] = current_knode;
		offsetD[bid] = offset_val;
	}
}

void 
kernel_cpu(	int cores_arg,
			record *records,
			knode *knodes,
			long knodes_elem,
			int order,
			long maxheight,
			int count,
			long *currKnode,
			long *offset,
			int *keys,
			record *ans)
{
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_mem_alloc_end;
	struct timeval tv_close_start, tv_close_end;
	struct timeval tv;
	float init_time = 0, mem_alloc_time = 0, kernel_time = 0, close_time = 0, total_time = 0;

#ifdef TIMING
	gettimeofday(&tv_total_start, NULL);
#endif

	// Simulate init time
#ifdef TIMING
	gettimeofday(&tv_init_end, NULL);
	timersub(&tv_init_end, &tv_total_start, &tv);
	init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	// Simulate mem alloc time
#ifdef TIMING
	gettimeofday(&tv_mem_alloc_end, NULL);
	timersub(&tv_mem_alloc_end, &tv_init_end, &tv);
	mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	// Execute kernel
#ifdef TIMING
	struct timeval tv_kernel_start, tv_kernel_end;
	gettimeofday(&tv_kernel_start, NULL);
#endif

	findK(maxheight, knodes, knodes_elem, records, currKnode, offset, keys, ans, count, order);

#ifdef TIMING
	gettimeofday(&tv_kernel_end, NULL);
	timersub(&tv_kernel_end, &tv_kernel_start, &tv);
	kernel_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

#ifdef TIMING
	gettimeofday(&tv_close_end, NULL);
	timersub(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
	timersub(&tv_close_end, &tv_total_start, &tv);
	total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
	printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", 0.0);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", 0.0);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif
}

void 
kernel_gpu_opencl_wrapper(	record *records,
							long records_mem,
							knode *knodes,
							long knodes_elem,
							long knodes_mem,
							int order,
							long maxheight,
							int count,
							long *currKnode,
							long *offset,
							int *keys,
							record *ans)
{
	kernel_cpu(1, records, knodes, knodes_elem, order, maxheight, count, currKnode, offset, keys, ans);
}

// Helper for timeval subtraction if not available in standard headers in some environments
void timersub(struct timeval *end, struct timeval *start, struct timeval *result) {
	result->tv_sec = end->tv_sec - start->tv_sec;
	result->tv_usec = end->tv_usec - start->tv_usec;
	if (result->tv_usec < 0) {
		result->tv_sec--;
		result->tv_usec += 1000000;
	}
}

