void 
findRangeK(	long height,
			knode *knodesD,
			long knodes_elem,
			long *currKnodeD,
			long *offsetD,
			long *lastKnodeD,
			long *offset_2D,
			int *startD,
			int *endD,
			int *RecstartD, 
			int *ReclenD,
			int count,
			int order)
{
	int local_size = (order < 1024) ? order : 1024;
	int num_blocks = count;

	#pragma omp parallel for num_threads(num_blocks)
	for(int bid = 0; bid < num_blocks; bid++) {
		int thid;
		long current_knode = currKnodeD[bid];
		long last_knode = lastKnodeD[bid];
		long offset_val = offsetD[bid];
		long offset_2_val = offset_2D[bid];

		int start_key = startD[bid];
		int end_key = endD[bid];

		for(int i = 0; i < height; i++) {
			knode *curr_node_ptr = &knodesD[current_knode];
			knode *last_node_ptr = &knodesD[last_knode];

			int found_curr_thid = -1;
			int found_last_thid = -1;

			for(thid = 0; thid < local_size; thid++) {
				if(thid < curr_node_ptr->num_keys - 1) {
					if((curr_node_ptr->keys[thid] <= start_key) && 
					   (curr_node_ptr->keys[thid+1] > start_key)) {
						found_curr_thid = thid;
						break;
					}
				}
			}

			for(thid = 0; thid < local_size; thid++) {
				if(thid < last_node_ptr->num_keys - 1) {
					if((last_node_ptr->keys[thid] <= end_key) && 
					   (last_node_ptr->keys[thid+1] > end_key)) {
						found_last_thid = thid;
						break;
					}
				}
			}

			if(found_curr_thid != -1) {
				if(knodesD[current_knode].indices[found_curr_thid] < knodes_elem) {
					offset_val = knodesD[current_knode].indices[found_curr_thid];
				}
			}

			if(found_last_thid != -1) {
				if(knodesD[last_knode].indices[found_last_thid] < knodes_elem) {
					offset_2_val = knodesD[last_knode].indices[found_last_thid];
				}
			}

			current_knode = offset_val;
			last_knode = offset_2_val;
		}

		knode *final_curr_node = &knodesD[current_knode];
		int found_final_start = -1;
		for(thid = 0; thid < local_size; thid++) {
			if(thid < final_curr_node->num_keys - 1) {
				if(final_curr_node->keys[thid] == start_key) {
					found_final_start = thid;
					break;
				}
			}
		}

		if(found_final_start != -1) {
			RecstartD[bid] = final_curr_node->indices[found_final_start];
		}

		knode *final_last_node = &knodesD[last_knode];
		int found_final_end = -1;
		for(thid = 0; thid < local_size; thid++) {
			if(thid < final_last_node->num_keys - 1) {
				if(final_last_node->keys[thid] == end_key) {
					found_final_end = thid;
					break;
				}
			}
		}

		if(found_final_end != -1) {
			ReclenD[bid] = final_last_node->indices[found_final_end] - RecstartD[bid] + 1;
		}

		currKnodeD[bid] = current_knode;
		lastKnodeD[bid] = last_knode;
		offsetD[bid] = offset_val;
		offset_2D[bid] = offset_2_val;
	}
}

